 80	// ForwardMutation routes a single owner-targeted mutation to the unique spoke
 81	// that owns the target project. It preserves the request metadata as headers so
 82	// the spoke can enforce origin and idempotency constraints.
 83	func (p *hubFederationProvider) ForwardMutation(ctx context.Context, req *federation.ForwardMutationRequest) (*federation.ForwardMutationResponse, error) {
 84		if p.server.hub == nil {
 85			return nil, federation.ErrForwardMutationOffline
 86		}
 87		if req == nil {
 88			return nil, federation.ErrForwardMutationBroadcastLike
 89		}
 90		if err := req.Validate(); err != nil {
 91			return nil, err
 92		}
 93	
 94		p.server.hub.mu.Lock()
 95		target, routeErr := federation.RouteMutationToProjectOwner(p.server.hub.registry, req.TargetProjectID)
 96		p.server.hub.mu.Unlock()
 97		if routeErr != nil {
 98			if strings.Contains(routeErr.Error(), "multiple registered owners") {
 99				return nil, &federation.ForwardMutationRefusalError{
100					Kind:   federation.ForwardMutationRefusalBroadcastLike,
101					Detail: routeErr.Error(),
102				}
103			}
104			return nil, &federation.ForwardMutationRefusalError{
105				Kind:   federation.ForwardMutationRefusalMissingOwner,
106				Detail: routeErr.Error(),
107			}
108		}
109	
110		targetCopy := *target
111		if targetCopy.NodeID != req.TargetNodeID {
112			return nil, &federation.ForwardMutationRefusalError{
113				Kind:   federation.ForwardMutationRefusalBroadcastLike,
114				Detail: fmt.Sprintf("target node %q does not own project %q", req.TargetNodeID, req.TargetProjectID),
115			}
116		}
117	
118		if targetCopy.Status == federation.StatusOffline {
119			return nil, federation.ErrForwardMutationOffline
120		}
121		if targetCopy.Status == federation.StatusStale {
122			return nil, federation.ErrForwardMutationStale
123		}
124		if !spokeHasCapability(targetCopy.Capabilities, "write") {
125			return nil, federation.ErrForwardMutationReadOnly
126		}
127	
128		headers := make(map[string]string, len(req.Headers)+5)
129		for k, v := range req.Headers {
130			headers[k] = v
131		}
132		if req.OriginIdentity != "" {
133			headers[federationOriginIdentityHeader] = req.OriginIdentity
134		}
135		if coordinatorIdentity := strings.TrimSpace(p.server.federationSelfIdentity()); coordinatorIdentity != "" {
136			headers[federationCoordinatorIdentityHeader] = coordinatorIdentity
137		}
138		if len(req.ForwardingPath) > 0 {
139			headers["X-DDx-Forwarding-Path"] = strings.Join(req.ForwardingPath, " -> ")
140		}
141		if req.RequestID != "" {
142			headers["X-DDx-Request-ID"] = req.RequestID
143		}
144		if req.IdempotencyKey != "" {
145			headers["X-DDx-Idempotency-Key"] = req.IdempotencyKey
146		}
147		if req.TargetProjectID != "" {
148			headers["X-DDx-Target-Project-ID"] = req.TargetProjectID
149		}
150		if req.ExpectedVersion != nil && *req.ExpectedVersion != "" {
151			headers["X-DDx-Expected-Version"] = *req.ExpectedVersion
152		}
153	
154		resp, err := federation.NewFanOutClient().ForwardMutation(ctx, &targetCopy, req.Body, headers)
155		if err != nil {
156			return nil, err
157		}
158		defer func() { _ = resp.Body.Close() }()
159	
160		body, err := io.ReadAll(resp.Body)
161		if err != nil {
162			return nil, err
163		}
164	
165		return &federation.ForwardMutationResponse{
166			OriginIdentity:       req.OriginIdentity,
167			ForwardingPath:       append([]string(nil), req.ForwardingPath...),
168			RequestID:            req.RequestID,
169			IdempotencyKey:       req.IdempotencyKey,
170			TargetNodeID:         req.TargetNodeID,
171			TargetProjectID:      req.TargetProjectID,
172			ExpectedVersion:      req.ExpectedVersion,
173			RequiredCapabilities: append([]string(nil), req.RequiredCapabilities...),
174			StatusCode:           resp.StatusCode,
175			Headers:              resp.Header.Clone(),
176			Body:                 body,
177		}, nil
178	}
